/**
 * wdpr-panel - Unified panel component
 * Desktop/Tablet: side panel (left/right) | Mobile: full-screen slide from left/right
 * Features: VisualViewport anchoring, focus trap, backdrop/ESC close, header variants
 */

import { Component, Prop, h, Element, Watch, Event, EventEmitter, Host, State } from '@stencil/core';
import { customTwMerge, generateRandId } from '../../utils/utils';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';

export type PanelPosition = 'left' | 'right';
export type HeaderBackgroundVariant = 'primary' | 'secondary' | 'media' | 'floatingButtons';

@Component({
  tag: 'wdpr-panel',
  styleUrl: 'wdpr-panel.css',
  shadow: true,
})
export class WdprPanel {
  // ────────────────────────── Public API ─────────────────────────

  @Element() el!: HTMLWdprPanelElement;

  /** Which side the panel slides from. */
  @Prop() position: PanelPosition = 'right';

  /** Open state (reflects). In uncontrolled mode this is mutated internally. */
  @Prop({ mutable: true, reflect: true }) isOpen = false;

  /** Title/Subtitle for fallback header + a11y. */
  @Prop() titleText = 'Title';
  @Prop() subtitleText = 'Subtitle';

  /** Optional leading icon for fallback header. */
  @Prop() leadingIcon?: string;

  /** Primary action label for fallback footer. */
  @Prop() buttonText = 'Primary Action';

  /** Enable close affordances (X, ESC, backdrop). */
  @Prop({ mutable: true, reflect: true }) isCloseable = true;

  /** Show optional "Back" button in header. */
  @Prop({ mutable: true, reflect: true }) showBackButton = false;

  /** Disable closing with the Escape key. */
  @Prop({ mutable: true, reflect: true }) disableEscClose = false;

  /** Desktop side-panel width (e.g., "26rem"). */
  @Prop() width: string = '26rem';

  /**
   * Header background variant:
   * - primary: page default background color (bg-page-default)
   * - secondary: surface default background color (bg-surface-default)
   * - media: supports image/media background via header-background slot
   * - floatingButtons: two floating circular icon buttons only, content scrolls behind
   */
  @Prop({ reflect: true }) headerBackground: HeaderBackgroundVariant = 'primary';

  /** Divider between header and content. */
  @Prop({ mutable: true, reflect: true }) showDivider = true;

  /** Show elevation shadow on header when scrolled. */
  @Prop({ mutable: true, reflect: true }) showElevation = true;

  /** Animation duration (ms). */
  @Prop() animationMs = 240;

  /** Close when tapping the backdrop. */
  @Prop({ mutable: true }) closeOnBackdrop = true;

  /** Controlled mode: do not mutate `isOpen` internally. */
  @Prop({ reflect: true }) controlled = false;

  /** Shows the footer section. by default is true */
  @Prop() showFooter = true;

  /** Decorative mode: disable focus trapping. */
  @Prop({ reflect: true }) decorative = false;

  // ─────────────────────────── Events ───────────────────────────

  @Event({ eventName: 'panelOpened' }) panelOpened!: EventEmitter<void>;
  @Event({ eventName: 'panelClosed' }) panelClosed!: EventEmitter<void>;
  @Event({ eventName: 'panelCloseRequested' }) panelCloseRequested!: EventEmitter<void>;
  @Event({ eventName: 'back' }) back!: EventEmitter<void>;
  @Event({ eventName: 'primaryAction' }) primaryAction!: EventEmitter<void>;

  // ───────────────────── Internal state/refs ────────────────────

  private _panelRef!: HTMLDivElement;
  private _footerRef!: HTMLElement;

  private _headingId = `wdpr-panel-h-${generateRandId()}`;
  private _previouslyFocusedEl: Element | null = null;

  @State() layoutIsMobile = false;
  @State() isBodyScrolled = false;

  private _prevLayoutIsMobile: boolean | null = null;
  private _mq?: MediaQueryList;

  private _footerHeight = 0;

  // focus trap
  private _focusableEls: HTMLElement[] = [];
  private _firstFocusableEl: HTMLElement | null = null;
  private _lastFocusableEl: HTMLElement | null = null;
  private _listenersAttached = false;
  private _isRefocusing = false;
  private _isSentinelHandoff = false;
  private _mo?: MutationObserver;

  private _resizeRaf?: number;

  private static FOCUSABLE_SELECTORS = [
    'a[href]',
    'area[href]',
    'button:not([disabled])',
    'input:not([disabled])',
    'select:not([disabled])',
    'textarea:not([disabled])',
    'iframe',
    '[tabindex]:not([tabindex="-1"])',
    '[contenteditable="true"]',
    'wdpr-button',
    'wdpr-icon-button',
    'wdpr-card-link',
    'wdpr-checkbox',
  ].join(',');

  // ────────────────────────── Layout mode ───────────────────────

  private _onMediaChange = (e: MediaQueryListEvent) => {
    this._prevLayoutIsMobile = this.layoutIsMobile;
    this.layoutIsMobile = e.matches;

    if (this._prevLayoutIsMobile === null || this._prevLayoutIsMobile === this.layoutIsMobile) return;
    if (!this._panelRef) return;

    this._syncLayoutForCurrentMode(true, false);
  };

  componentWillLoad() {
    if (typeof window !== 'undefined' && 'matchMedia' in window) {
      this._mq = window.matchMedia('(max-width: 767px)');
      this.layoutIsMobile = this._mq.matches;
      this._syncViewportCSSVars();
      this._mq.addEventListener('change', this._onMediaChange);
      window.addEventListener('orientationchange', this._onViewportResize);
      window.visualViewport?.addEventListener('scroll', this._onViewportResize, { passive: true });
    }
  }

  componentDidLoad(): void {
    if (this.isOpen) this._onOpen(false);
    window.visualViewport?.addEventListener('resize', this._onViewportResize);
    window.addEventListener('resize', this._onViewportResize);
    this._syncViewportCSSVars();
  }

  disconnectedCallback(): void {
    this._mq?.removeEventListener('change', this._onMediaChange);
    this._detachGlobalListeners();
    document.body.classList.remove('overflow-hidden');
    this._mo?.disconnect();
    this._mo = undefined;
    window.visualViewport?.removeEventListener('resize', this._onViewportResize);
    window.removeEventListener('resize', this._onViewportResize);
    window.removeEventListener('orientationchange', this._onViewportResize);
    window.visualViewport?.removeEventListener('scroll', this._onViewportResize);
  }

  @Watch('isOpen')
  onOpenChanged(): void {
    if (this.isOpen) {
      this._onOpen(true);
    } else {
      this._onClose(true);
    }
  }

  // ───────────────────────── Viewport utils ─────────────────────

  /** Sync CSS variables for VisualViewport geometry. */
  private _syncViewportCSSVars(): void {
    const vv = window.visualViewport;
    const vw = Math.round(vv?.width ?? document.documentElement.clientWidth ?? window.innerWidth ?? 0);
    const vh = Math.round(vv?.height ?? document.documentElement.clientHeight ?? window.innerHeight ?? 0);
    const top = Math.round(vv?.offsetTop ?? 0);
    const left = Math.round(vv?.offsetLeft ?? 0);

    if (this._footerRef && this.showFooter) {
      this._footerHeight = this._footerRef.clientHeight;
    } else {
      this._footerHeight = 0;
    }

    this.el.style.setProperty('--vvh', `${vh}px`);
    this.el.style.setProperty('--pbottom', `${this._footerHeight}px`);
    this.el.style.setProperty('--vvw', `${vw}px`);
    this.el.style.setProperty('--vvtop', `${top}px`);
    this.el.style.setProperty('--vvleft', `${left}px`);
  }

  // ─────────────────────── Open / Close flow ────────────────────

  private _onOpen(animate: boolean): void {
    this.isBodyScrolled = false;
    this.panelOpened.emit();
    this._rememberOpener();
    document.body.classList.add('overflow-hidden');

    // Position panel off-screen immediately without transition
    if (this._panelRef) {
      this._panelRef.style.transition = 'none';
      const offScreen = this.position === 'right' ? 'translateX(100%)' : 'translateX(-100%)';
      this._panelRef.style.transform = offScreen;
    }

    // Also hide footer immediately
    if (this._footerRef) {
      this._footerRef.style.transition = 'none';
      const offScreen = this.position === 'right' ? 'translateX(100%)' : 'translateX(-100%)';
      this._footerRef.style.transform = offScreen;
    }

    // Observe internal mutations to keep the focus trap fresh.
    if (typeof MutationObserver !== 'undefined') {
      this._mo = new MutationObserver(() => this._prepareFocusTrap());
      this._mo.observe(this._panelRef, { subtree: true, childList: true });
    }

    this._prepareFocusTrap();
    this._attachGlobalListeners();

    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        if (!this.isOpen) return;
        this._syncViewportCSSVars();
        this._syncLayoutForCurrentMode(animate, true);
      });
    });

    // Handoff initial focus.
    setTimeout(() => (this._firstFocusableEl ?? this._panelRef).focus({ preventScroll: true }), 0);
  }

  private _onClose(animate: boolean): void {
    this.isBodyScrolled = false;
    this.panelClosed.emit();
    this._detachGlobalListeners();
    document.body.classList.remove('overflow-hidden');

    this._mo?.disconnect();
    this._mo = undefined;

    this._syncLayoutForCurrentMode(animate, false);

    this._focusableEls = [];
    this._firstFocusableEl = null;
    this._lastFocusableEl = null;

    this._restoreFocus();
  }

  // ────────────────────────── Layout sync ───────────────────────

  /** Recompute transforms/targets for current mode. */
  private _syncLayoutForCurrentMode(animate: boolean, isInitialOpen = false): void {
    if (!this._panelRef) {
      return;
    }

    // Both mobile (full-screen) and desktop use slide from left/right
    if (this.isOpen) {
      if (animate && isInitialOpen) {
        // Set initial off-screen position without transition
        const offScreenTransform = this.position === 'right' ? 'translateX(100%)' : 'translateX(-100%)';
        this._panelRef.style.transition = 'none';
        this._panelRef.style.transform = offScreenTransform;

        if (this._footerRef) {
          this._footerRef.style.transition = 'none';
          this._footerRef.style.transform = offScreenTransform;
        }

        // Short delay to ensure initial state is painted, then enable transition and animate
        setTimeout(() => {
          this._panelRef.style.transition = '';
          this._panelRef.classList.add('animating');
          this._panelRef.style.transform = 'translateX(0)';

          if (this._footerRef) {
            this._footerRef.style.transition = `transform ${this.animationMs}ms cubic-bezier(.22, .61, .36, 1)`;
            this._footerRef.style.transform = 'translateX(0)';
          }

          window.setTimeout(() => {
            this._panelRef.classList.remove('animating');
            if (this._footerRef) this._footerRef.style.transition = '';
          }, this.animationMs);
        }, 20);
      } else {
        this._panelRef.style.transform = 'translateX(0)';
        if (this._footerRef) this._footerRef.style.transform = 'translateX(0)';
      }
    } else {
      const translateDir = this.position === 'right' ? '100%' : '-100%';

      if (animate) {
        this._panelRef.classList.add('animating');
        this._panelRef.style.transform = `translateX(${translateDir})`;

        if (this._footerRef) {
          this._footerRef.style.transition = `transform ${this.animationMs}ms cubic-bezier(.22, .61, .36, 1)`;
          this._footerRef.style.transform = `translateX(${translateDir})`;
        }

        window.setTimeout(() => {
          this._panelRef.classList.remove('animating');
          if (this._footerRef) this._footerRef.style.transition = '';
        }, this.animationMs);
      } else {
        this._panelRef.style.transform = `translateX(${translateDir})`;
        if (this._footerRef) this._footerRef.style.transform = `translateX(${translateDir})`;
      }
    }
  }

  /** Throttled viewport listener. */
  private _onViewportResize = () => {
    if (!this.isOpen) return;
    if (this._resizeRaf) cancelAnimationFrame(this._resizeRaf);
    this._resizeRaf = requestAnimationFrame(() => {
      this._syncViewportCSSVars();
      this._syncLayoutForCurrentMode(false, false);
    });
  };

  // ────────────────────────── A11y / Focus ──────────────────────

  private _getLocalActiveElement(): Element | null {
    const root = this.el.getRootNode() as Document | ShadowRoot;

    return root.activeElement ?? null;
  }

  private _rememberOpener(): void {
    this._previouslyFocusedEl = this._getLocalActiveElement();
  }

  private _isFocusable(el: Element | null | undefined): el is HTMLElement {
    if (!(el instanceof HTMLElement)) {
      return false;
    }
    if (!el.isConnected) {
      return false;
    }
    if (el['disabled']) {
      return false;
    }

    return typeof el.focus === 'function';
  }

  /** Deep focus attempt into host/shadow child control. */
  private _focusDeep(el: HTMLElement | null | undefined): boolean {
    if (!el) return false;
    const root = this.el.getRootNode() as Document | ShadowRoot;
    const dsr = root as DocumentOrShadowRoot;
    try {
      el.focus({ preventScroll: true });
    } catch {}
    if (dsr.activeElement === el) return true;

    const sr = (el as HTMLElement).shadowRoot as ShadowRoot | undefined;
    if (sr) {
      const inner = sr.querySelector<HTMLElement>('button,[href],input,select,textarea,[tabindex]:not([tabindex="-1"])');
      if (inner) {
        try {
          inner.focus({ preventScroll: true });
        } catch {}
        if (dsr.activeElement === el || dsr.activeElement === inner) return true;
      }
    }

    return false;
  }

  /** Reasonable focus return target when the original opener is gone. */
  private _findFallbackFocus(): HTMLElement | null {
    const tagged = document.querySelector<HTMLElement>('[data-return-focus]');
    if (tagged && this._isFocusable(tagged)) return tagged;

    let cur: HTMLElement | null = this.el as HTMLElement;
    while (cur) {
      if (this._isFocusable(cur)) return cur;
      cur = (cur as HTMLElement).parentElement as HTMLElement | null;
    }

    const main = document.querySelector<HTMLElement>('main, [role="main"], [tabindex="0"]');
    if (main && this._isFocusable(main)) return main;

    return document.body as unknown as HTMLElement;
  }

  private _restoreFocus(): void {
    const target = (this._previouslyFocusedEl as HTMLElement) ?? null;
    requestAnimationFrame(() => {
      if (!this._focusDeep(target)) this._focusDeep(this._findFallbackFocus());
    });
  }

  private _findFocusable(root: Element | ShadowRoot): HTMLElement[] {
    const seen = new Set<HTMLElement>();
    const els: HTMLElement[] = [];

    const isFocusable = (el: HTMLElement) => {
      return (
        el.matches(WdprPanel.FOCUSABLE_SELECTORS) &&
        !el.hasAttribute('disabled') &&
        el.getAttribute('aria-disabled') !== 'true' &&
        el.tabIndex !== -1 &&
        !el.hasAttribute('data-focus-sentinel')
      );
    };

    const addFocusable = (el: HTMLElement) => {
      if (!seen.has(el)) {
        seen.add(el);
        els.push(el);
      }
    };

    const walk = (curr: Element | ShadowRoot) => {
      if (curr.nodeName === 'SLOT') {
        const slot = curr as HTMLSlotElement;
        const assigned = slot.assignedElements({ flatten: true });

        if (assigned.length > 0) {
          assigned.forEach(node => {
            if (node instanceof HTMLElement) {
              if (isFocusable(node)) addFocusable(node);

              walk(node);
              if (node.shadowRoot) walk(node.shadowRoot);
            }
          });
        } else {
          const defaultContent = Array.from(slot.children || []);
          for (const child of defaultContent) {
            if (child instanceof HTMLElement) {
              if (isFocusable(child)) addFocusable(child);
              walk(child);
              if (child.shadowRoot) walk(child.shadowRoot);
            }
          }
        }

        return;
      }

      const children = Array.from(curr.children || (curr as ShadowRoot).children || []);

      for (const child of children) {
        if (!(child instanceof HTMLElement)) continue;

        if (isFocusable(child)) {
          addFocusable(child);
        }

        walk(child);
        if (child.shadowRoot) {
          walk(child.shadowRoot);
        }
      }
    };

    walk(root);

    return els;
  }

  private _prepareFocusTrap(): void {
    const allFocusables = this._findFocusable(this._panelRef);

    this._focusableEls = [...allFocusables];
    this._firstFocusableEl = this._focusableEls[0] ?? null;
    this._lastFocusableEl = this._focusableEls[this._focusableEls.length - 1] ?? null;
  }

  private _getCurrentFocusableFromEvent(e: KeyboardEvent): HTMLElement | null {
    const path = (e.composedPath?.() ?? []) as EventTarget[];

    const t0 = path[0];
    if (t0 instanceof HTMLElement && this._focusableEls.includes(t0)) return t0;

    const inPath = path.find(t => t instanceof HTMLElement && this._focusableEls.includes(t as HTMLElement)) as HTMLElement | undefined;
    if (inPath) return inPath;

    const root = this.el.getRootNode() as Document | ShadowRoot;
    const active = root.activeElement as HTMLElement | null;

    return active && this._focusableEls.includes(active) ? active : null;
  }

  private _attachGlobalListeners(): void {
    if (this._listenersAttached) return;
    document.addEventListener('keydown', this._onKeydown, true);
    document.addEventListener('focusin', this._onDocFocusIn, true);
    this._listenersAttached = true;
  }

  private _detachGlobalListeners(): void {
    if (!this._listenersAttached) return;
    document.removeEventListener('keydown', this._onKeydown, true);
    document.removeEventListener('focusin', this._onDocFocusIn, true);
    this._listenersAttached = false;
  }

  /** Check if there's an open drawer that should handle focus/keyboard instead of panel */
  private _hasOpenDrawer(): boolean {
    const openDrawer = document.querySelector('wdpr-drawer[is-open]') as HTMLElement | null;
    if (!openDrawer) return false;
    const attr = openDrawer.getAttribute('is-open');

    return attr !== null && attr !== 'false';
  }

  private _onDocFocusIn = (e: FocusEvent): void => {
    if (!this.isOpen || this._isRefocusing || this._isSentinelHandoff) return;

    // Check if there's an open drawer - if so, let the drawer handle focus
    if (this._hasOpenDrawer()) return;

    const path = (e.composedPath?.() ?? []) as EventTarget[];
    // Allow focus in both panel and footer
    const isInPanel = this._panelRef && path.includes(this._panelRef);
    const isInFooter = this._footerRef && path.includes(this._footerRef);
    if (!isInPanel && !isInFooter) {
      this._isRefocusing = true;
      try {
        this._prepareFocusTrap();
        (this._firstFocusableEl ?? this._panelRef).focus({ preventScroll: true });
        e.stopImmediatePropagation();
        e.preventDefault();
      } finally {
        this._isRefocusing = false;
      }
    }
  };

  private _onKeydown = (e: KeyboardEvent): void => {
    if (!this.isOpen || e.defaultPrevented) return;

    if (this._hasOpenDrawer()) return;

    if (e.key === KEYBOARD_KEYS.ESCAPE && !this.disableEscClose) {
      e.stopPropagation();
      this._closePanel();

      return;
    }

    if (e.key !== KEYBOARD_KEYS.TAB) return;

    this._prepareFocusTrap();

    const current = this._getCurrentFocusableFromEvent(e);
    const count = this._focusableEls.length;

    if (count === 0) {
      e.preventDefault();
      this._panelRef.focus();

      return;
    }

    if (!e.shiftKey && current === this._lastFocusableEl) {
      e.preventDefault();
      this._firstFocusableEl?.focus({ preventScroll: true });

      return;
    }

    const isFirst = current === this._firstFocusableEl || current === this._panelRef;
    if (e.shiftKey && isFirst) {
      e.preventDefault();
      this._lastFocusableEl?.focus({ preventScroll: true });

      return;
    }

    e.preventDefault();
    const currentIdx = current ? this._focusableEls.indexOf(current) : -1;
    let nextIdx = e.shiftKey ? currentIdx - 1 : currentIdx + 1;

    if (nextIdx < 0) nextIdx = count - 1;
    if (nextIdx >= count) nextIdx = 0;

    this._focusableEls[nextIdx]?.focus({ preventScroll: true });
  };

  private _closePanel(): void {
    if (this.controlled) {
      this.panelCloseRequested.emit();
    } else {
      this.isOpen = false;
    }
  }

  // ─────────────────────── Render helpers ───────────────────────

  private get _isMobileFullScreen(): boolean {
    return this.layoutIsMobile;
  }

  private get _panelWidthClass(): string {
    return 'max-w-[100vw]';
  }

  private get _sideTransformClass(): string {
    return this.position === 'right' ? 'right-0 left-auto translate-x-full' : 'left-0 right-auto -translate-x-full';
  }

  private get _sideRadiusClass(): string {
    // Mobile full-screen has no border radius
    if (this._isMobileFullScreen) {
      return '';
    }

    return this.position === 'right' ? 'rounded-tl-400 rounded-bl-400 rounded-tr-none rounded-br-none' : 'rounded-tr-400 rounded-br-400 rounded-tl-none rounded-bl-none';
  }

  private get _sideRadiusHeaderClass(): string {
    if (this._isMobileFullScreen) {
      return '';
    }

    return this.position === 'right' ? 'rounded-tl-400 rounded-bl-none rounded-tr-none rounded-br-none' : 'rounded-tr-400 rounded-br-none rounded-tl-none rounded-bl-none';
  }

  private get _sideRadiusFooterClass(): string {
    if (this._isMobileFullScreen) {
      return '';
    }

    return this.position === 'right' ? 'rounded-bl-400 rounded-tl-none rounded-tr-none rounded-br-none' : 'rounded-br-400 rounded-tr-none rounded-tl-none rounded-bl-none';
  }

  /** Wrapper around content+footer: overflow-hidden + bottom radius so panel clips bottom corner without breaking header backdrop-filter. */
  private get _sideRadiusContentWrapperClass(): string {
    if (this._isMobileFullScreen) {
      return '';
    }

    return this.position === 'right' ? 'rounded-bl-400 rounded-tl-none rounded-tr-none rounded-br-none' : 'rounded-br-400 rounded-tr-none rounded-tl-none rounded-bl-none';
  }

  private get _panelBgClass(): string {
    switch (this.headerBackground) {
      case 'secondary':
        return 'bg-surface-default';
      case 'primary':
      default:
        return 'bg-page-default';
    }
  }

  /** Desktop width; mobile uses full width. */
  private get _panelStyle(): Record<string, string> {
    if (this._isMobileFullScreen) {
      return { width: '100vw', maxWidth: '100vw' };
    }

    const w = this.width && this.width !== '' ? this.width : '26rem';

    return { width: w, maxWidth: '100vw' };
  }

  private get _panelLayoutClasses(): string {
    const baseClasses = customTwMerge(
      'fixed top-0 bottom-0',
      this._sideTransformClass,
      this.isOpen ? 'translate-x-0' : '',
      'flex flex-col',
      'items-stretch content-stretch',
      this._panelBgClass,
      this._sideRadiusClass,
      this._panelWidthClass,
      'transition-transform duration-300 ease-[cubic-bezier(.22,.61,.36,1)]',
      'pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)]',
      'pointer-events-auto',
      'h-full max-h-full overflow-visible',
      'z-20',
    );

    return `${baseClasses} panel-content`;
  }

  private _getHeaderBackgroundColor(): string {
    if (this._isFloatingButtons) return 'bg-transparent';

    switch (this.headerBackground) {
      case 'secondary':
        return this.isBodyScrolled ? 'bg-surface-translucent' : 'bg-surface-default';
      case 'media':
        return this.isBodyScrolled ? 'bg-surface-translucent' : 'bg-transparent';
      case 'primary':
      default:
        return 'bg-page-default';
    }
  }

  private get _isFloatingButtons(): boolean {
    return this.headerBackground === 'floatingButtons';
  }

  private get _headerClasses(): string {
    const positionClass = this._isFloatingButtons ? 'absolute top-0 left-0 right-0 z-30' : 'sticky top-0 z-30';
    const headerColor = this._getHeaderBackgroundColor();

    let classes = `${positionClass} flex flex-col w-full transition-colors duration-200 ${headerColor} ${this._sideRadiusHeaderClass}`;

    if (this.showElevation && this.isBodyScrolled && !this._isFloatingButtons) {
      classes += ' elevation-xsmall-soft';
    }

    if (this._isFloatingButtons && !this._isMobileFullScreen) {
      classes += ' overflow-hidden';
    }

    return classes;
  }

  private _clickPrimary(): void {
    this.primaryAction.emit();
  }

  private _overlayClick(): void {
    if (this.closeOnBackdrop) this._closePanel();
  }

  // ────────────────────── Render-time handlers ──────────────────

  private _handleOverlayClick = (ev: CustomEvent<void>): void => {
    ev.stopPropagation();
    this._overlayClick();
  };

  private _handleBackClick = (ev: Event): void => {
    ev.stopPropagation();
    this.back.emit();
  };

  private _handleCloseClick = (ev: Event): void => {
    ev.stopPropagation();
    this._closePanel();
  };

  private _handlePrimaryClick = (ev: Event): void => {
    ev.stopPropagation();
    this._clickPrimary();
  };

  private _handleScrollChange = (ev: CustomEvent<{ position: number }>): void => {
    const position = ev?.detail?.position ?? 0;
    if (this.isBodyScrolled !== position > 0) {
      this.isBodyScrolled = position > 0;
    }
  };

  private _handleSentinelFocus(isStart: boolean): void {
    if (!this.isOpen) return;
    const target = isStart ? this._lastFocusableEl : this._firstFocusableEl;
    this._isSentinelHandoff = true;
    setTimeout(() => {
      (target ?? this._panelRef).focus();
      this._isSentinelHandoff = false;
    }, 0);
  }

  // ─────────────────────────── Rendering ────────────────────────

  render() {
    const labelledBy = this.titleText ? this._headingId : undefined;
    const ariaLabel = labelledBy ? undefined : this.titleText || 'Panel';
    const hasMediaBackground = this.headerBackground === 'media';

    const headerStyle =
      this.isBodyScrolled && !this._isFloatingButtons
        ? {
            backdropFilter: 'blur(calc(var(--effect-400, 32px) / 2))',
            WebkitBackdropFilter: 'blur(calc(var(--effect-400, 32px) / 2))',
          }
        : {};

    return (
      <Host style={{ '--anim-ms': `${this.animationMs}ms` }}>
        <wdpr-overlay cover open={this.isOpen} variant="scrim" role="presentation" a11y-label="Backdrop" onOverlayClick={this._handleOverlayClick} />

        {/* Panel */}
        <div
          style={this._panelStyle}
          class={this._panelLayoutClasses}
          part="panel"
          role="dialog"
          aria-modal="true"
          tabIndex={-1}
          aria-label={ariaLabel}
          aria-labelledby={labelledBy}
          ref={el => (this._panelRef = el as HTMLDivElement)}
        >
          {/* Focus sentinel (start) */}
          <div data-focus-sentinel="start" tabIndex={this.decorative ? -1 : 0} aria-hidden="true" class="sr-only" onFocus={() => this._handleSentinelFocus(true)} />

          <header class={this._headerClasses} style={headerStyle} part="header">
            {this._isFloatingButtons && (
              <div
                class="absolute top-0 left-0 right-0 h-[100px] pointer-events-none z-10"
                style={{
                  background: 'linear-gradient(to bottom, var(--bg-surface-default) 0%, var(--bg-surface-default) 30%, rgba(255, 255, 255, 0) 100%)',
                  backdropFilter: 'blur(12px)',
                  WebkitBackdropFilter: 'blur(12px)',
                }}
              />
            )}

            {hasMediaBackground && (
              <div class="absolute inset-0 z-0 overflow-hidden pointer-events-none">
                <slot name="header-background" />
              </div>
            )}

            <div class="relative w-full z-20">
              <slot name="panel-header">
                <wdpr-page-header
                  class={customTwMerge('w-full block pt-300', this._sideRadiusHeaderClass)}
                  titleText=""
                  sticky={false}
                  showElevation={false}
                  background="transparent"
                  onLeadingClick={this._handleBackClick}
                  onTrailingClick={this._handleCloseClick}
                >
                  {/* Leading Icon */}
                  {this.showBackButton && (
                    <wdpr-icon-button
                      slot="leading-icon"
                      iconName="back-thick"
                      a11yLabel="Back"
                      size="medium"
                      variant={this._isFloatingButtons ? 'bgPrimary' : 'primary'}
                      onClick={this._handleBackClick}
                    />
                  )}

                  {/* Trailing Icons */}
                  <div slot="trailing-icon" class="flex gap-100">
                    <slot name="header-actions" />
                    {this.isCloseable && (
                      <wdpr-icon-button
                        iconName="close-reversed"
                        a11yLabel="Close"
                        size="medium"
                        variant={this._isFloatingButtons ? 'bgPrimary' : 'primary'}
                        onClick={this._handleCloseClick}
                      />
                    )}
                  </div>

                  {/* Title/content section - hide for floating buttons variant */}
                  {!this._isFloatingButtons && (
                    <div slot="below" class="flex flex-col w-full">
                      <slot name="header">
                        <wdpr-text-header id={this._headingId} class="px-150 pb-200" headerLabel={this.titleText} subtextLabel={this.subtitleText}>
                          {this.leadingIcon && <wdpr-icon-library size="medium" icon={this.leadingIcon} slot="leading-icon" />}
                        </wdpr-text-header>
                      </slot>
                      <slot name="header-content" />
                    </div>
                  )}
                </wdpr-page-header>
              </slot>
            </div>

            <div
              style={{ display: this.showDivider && this.isBodyScrolled && !this._isFloatingButtons ? 'block' : 'none' }}
              aria-hidden={!(this.showDivider && this.isBodyScrolled && !this._isFloatingButtons) ? 'true' : null}
            >
              <wdpr-divider orientation="horizontal" class="w-full block relative z-30" />
            </div>
          </header>

          {/* Content + footer wrapper: overflow-hidden + bottom radius clips bottom corner without breaking header backdrop-filter */}
          <div class={customTwMerge('flex flex-col flex-1 min-h-0 overflow-hidden', this._sideRadiusContentWrapperClass)}>
            {/* Content */}
            <section class="min-w-0 min-h-0 flex flex-col flex-1 overflow-hidden" part="content">
              <wdpr-scrollbar orientation="vertical" size="medium" class="flex-1 min-h-0" onScrollChange={this._handleScrollChange}>
                {/* Add padding inside scrollable area for floating buttons so content can scroll behind */}
                <div style={{ display: 'block', height: 'auto' }}>
                  {this._isFloatingButtons && <div class="h-[60px] shrink-0" />}
                  <slot name="body" />
                </div>
              </wdpr-scrollbar>
            </section>

            {/* Footer */}
            {this.showFooter && (
              <footer ref={el => (this._footerRef = el as HTMLElement)} part="footer" class={customTwMerge('sticky bottom-0 z-[100000] w-full', this._sideRadiusFooterClass)}>
                <slot name="footer">
                  <wdpr-button-dock>
                    <wdpr-button-bar slot="button-bar" layout="stacked">
                      <wdpr-button display="block" slot="primary-button" variant="primary" size="large" onClick={this._handlePrimaryClick}>
                        {this.buttonText}
                      </wdpr-button>
                    </wdpr-button-bar>
                  </wdpr-button-dock>
                </slot>
              </footer>
            )}
          </div>
        </div>

        {/* Focus sentinel (end) - after footer so footer is in tab order */}
        <div data-focus-sentinel="end" tabIndex={this.decorative ? -1 : 0} aria-hidden="true" class="sr-only" onFocus={() => this._handleSentinelFocus(false)} />
      </Host>
    );
  }
}
